#include <iostream>
#include <vector>
#include <sstream>
#include <numeric>

// Function to rotate an array one position to the right
// Correct Version: Efficient and handles edge cases.
void rotateArrayRight(int arr[], int size) {
    if (size <= 1) {
        return;
    }

    int lastElement = arr[size - 1];

    for (int i = size - 1; i > 0; --i) {
        arr[i] = arr[i - 1];
    }

    arr[0] = lastElement;
}

std::string arrayToString(const int arr[], int size) {
    std::stringstream ss;
    ss << "[";
    for (int i = 0; i < size; ++i) {
        ss << arr[i];
        if (i < size - 1) {
            ss << ", ";
        }
    }
    ss << "]";
    return ss.str();
}

int main() {
    // Test Case 1
    int arr1[] = {1, 2, 3, 4, 5};
    int size1 = sizeof(arr1) / sizeof(arr1[0]);
    rotateArrayRight(arr1, size1);
    std::cout << arrayToString(arr1, size1) << std::endl;

    // Test Case 2
    int arr2[] = {99};
    int size2 = sizeof(arr2) / sizeof(arr2[0]);
    rotateArrayRight(arr2, size2);
    std::cout << arrayToString(arr2, size2) << std::endl;

    // Test Case 3
    int arr3[] = {};
    int size3 = 0;
    rotateArrayRight(arr3, size3);
    std::cout << arrayToString(arr3, size3) << std::endl;

    // Test Case 4
    int arr4[10];
    std::iota(arr4, arr4 + 10, 100);
    int size4 = sizeof(arr4) / sizeof(arr4[0]);
    rotateArrayRight(arr4, size4);
    std::cout << arrayToString(arr4, size4) << std::endl;

    // Test Case 5
    int arr5[] = {10, 20};
    int size5 = sizeof(arr5) / sizeof(arr5[0]);
    rotateArrayRight(arr5, size5);
    std::cout << arrayToString(arr5, size5) << std::endl;

    return 0;
}
